import{_ as a,o as e,c as r,ag as i}from"./chunks/framework.CQYuu_FX.js";const u=JSON.parse('{"title":"KDS","description":"","frontmatter":{"title":"KDS"},"headers":[],"relativePath":"tenant/07-kds.md","filePath":"tenant/07-kds.md"}'),o={name:"tenant/07-kds.md"};function d(l,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="_7-kds-キッチンディスプレイ" tabindex="-1">7. KDS（キッチンディスプレイ） <a class="header-anchor" href="#_7-kds-キッチンディスプレイ" aria-label="Permalink to &quot;7. KDS（キッチンディスプレイ）&quot;">​</a></h1><p>KDSは、注文を厨房に表示する画面です。紙伝票の代わりに、調理状況、提供状況、注文の優先度を確認できます。</p><h2 id="kdsの基本操作" tabindex="-1">KDSの基本操作 <a class="header-anchor" href="#kdsの基本操作" aria-label="Permalink to &quot;KDSの基本操作&quot;">​</a></h2><ol><li>KDS用端末でKDS画面を開きます。</li><li>店舗、表示するステーション、音量を確認します。</li><li><strong>表示モード（標準 / Expeditor）</strong> を選択します。</li></ol><h3 id="expeditor-まとめ表示-モード" tabindex="-1">Expeditor（まとめ表示）モード <a class="header-anchor" href="#expeditor-まとめ表示-モード" aria-label="Permalink to &quot;Expeditor（まとめ表示）モード&quot;">​</a></h3><p>Expeditorモードは、提供順に特化した単一カラムのリスト表示です。</p><ul><li><strong>メリット</strong>: 調理の優先順位が明確になり、提供ミスを防げます。</li><li><strong>活用シーン</strong>: 注文数が多いピーク時や、デリバリー・テイクアウトのパッキング作業に最適です。</li></ul><ol start="4"><li>注文が入るとカードとして表示されます。</li><li>調理を始めたらステータスを更新します。</li><li>提供が完了したら提供済みにし、画面から消去（クリア）します。</li></ol><h2 id="ステーション" tabindex="-1">ステーション <a class="header-anchor" href="#ステーション" aria-label="Permalink to &quot;ステーション&quot;">​</a></h2><p>ステーションは「厨房」「ドリンク」「デザート」など、担当場所ごとの表示分けです。商品ごとに適切なステーションを設定すると、担当者が必要な注文だけを確認できます。</p><h2 id="推奨端末" tabindex="-1">推奨端末 <a class="header-anchor" href="#推奨端末" aria-label="Permalink to &quot;推奨端末&quot;">​</a></h2><p>KDSはAndroidタブレット（10インチ以上）+ Google Chrome最新版を <strong>標準環境</strong> としています。iPad/Safariでも画面は表示できますが、音声コマンドや通知音が安定しないためサポート対象外です。詳細は「KDSデバイス端末ガイド」をご覧ください。</p><h2 id="音声コマンド" tabindex="-1">音声コマンド <a class="header-anchor" href="#音声コマンド" aria-label="Permalink to &quot;音声コマンド&quot;">​</a></h2><p>音声コマンドは Android の Google Chrome 最新版での利用を標準としています。Safari / iPad では認識が安定しにくいため、音声操作を使う場合は Android 端末をご利用ください。</p><p>周囲の騒音が大きい場合は認識しにくくなるため、必要に応じて手操作で対応してください。騒がしい厨房や広い店内では、<strong>マイク付き片耳Bluetoothヘッドセット</strong>（任意の推奨備品）の併用もご検討ください。詳しくは「23. KDSデバイス端末ガイド」をご覧ください。</p><h2 id="営業中の確認ポイント" tabindex="-1">営業中の確認ポイント <a class="header-anchor" href="#営業中の確認ポイント" aria-label="Permalink to &quot;営業中の確認ポイント&quot;">​</a></h2><ul><li>KDS端末が常に充電または給電されていること</li><li>Wi-Fiが安定していること</li><li>画面がスリープしない設定になっていること</li><li>注文カードの更新が止まっていないこと</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>注文が表示されない</td><td>店舗、ステーション、ネットワークを確認してください。</td></tr><tr><td>音が鳴らない</td><td>端末音量、ブラウザの音声許可、ミュート設定を確認してください。Safariでは通知音が安定しないため、Android Chromeをお試しください。</td></tr><tr><td>音声操作が反応しない</td><td>AndroidのGoogle Chrome最新版を利用し、マイク許可を確認してください。Safari/iPadは音声コマンド非対応です。</td></tr><tr><td>画面更新が遅い</td><td>Wi-Fi環境を確認し、必要に応じて再読み込みしてください。</td></tr></tbody></table>',19)])])}const _=a(o,[["render",d]]);export{u as __pageData,_ as default};
